import{_ as n,c as i,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"AI App Factory Best Practices: Produktbeschreibung, Checkpoints, Umfang und iterative Entwicklung | Tutorial","description":"Meistern Sie die AI App Factory Best Practices, um die Qualität und Effizienz von KI-generierten Anwendungen zu verbessern. Lernen Sie, klare Produktbeschreibungen zu schreiben, Checkpoints zur Qualitätskontrolle zu nutzen, Nicht-Ziele zur Vermeidung von Scope Creep zu definieren, Ideen iterativ zu validieren, Tokens durch separate Sessions zu sparen und mit Fehlern und Wiederholungen umzugehen. Dieses Tutorial behandelt sechs Schlüsseltechniken: Eingabequalität, Checkpoint-Validierung, MVP-Kontrolle, iterative Entwicklung, Kontextoptimierung und Fehlerbehandlung.","frontmatter":{"title":"AI App Factory Best Practices: Produktbeschreibung, Checkpoints, Umfang und iterative Entwicklung | Tutorial","sidebarTitle":"Best Practices","subtitle":"Best Practices: Klare Beschreibung, Checkpoint-Nutzung, Umfangskontrolle und Iterationstechniken","description":"Meistern Sie die AI App Factory Best Practices, um die Qualität und Effizienz von KI-generierten Anwendungen zu verbessern. Lernen Sie, klare Produktbeschreibungen zu schreiben, Checkpoints zur Qualitätskontrolle zu nutzen, Nicht-Ziele zur Vermeidung von Scope Creep zu definieren, Ideen iterativ zu validieren, Tokens durch separate Sessions zu sparen und mit Fehlern und Wiederholungen umzugehen. Dieses Tutorial behandelt sechs Schlüsseltechniken: Eingabequalität, Checkpoint-Validierung, MVP-Kontrolle, iterative Entwicklung, Kontextoptimierung und Fehlerbehandlung.","tags":["Best Practices","MVP","Iterative Entwicklung"],"prerequisite":["start-getting-started","start-pipeline-overview"],"order":200},"headers":[],"relativePath":"de/hyz1992/agent-app-factory/faq/best-practices/index.md","filePath":"de/hyz1992/agent-app-factory/faq/best-practices/index.md"}'),s={name:"de/hyz1992/agent-app-factory/faq/best-practices/index.md"};function a(l,e,o,h,u,d){return t(),i("div",null,[...e[0]||(e[0]=[r(`<h1 id="best-practices-klare-beschreibung-checkpoint-nutzung-umfangskontrolle-und-iterationstechniken" tabindex="-1">Best Practices: Klare Beschreibung, Checkpoint-Nutzung, Umfangskontrolle und Iterationstechniken <a class="header-anchor" href="#best-practices-klare-beschreibung-checkpoint-nutzung-umfangskontrolle-und-iterationstechniken" aria-label="Permalink to &quot;Best Practices: Klare Beschreibung, Checkpoint-Nutzung, Umfangskontrolle und Iterationstechniken&quot;">​</a></h1><h2 id="was-sie-nach-abschluss-konnen" tabindex="-1">Was Sie nach Abschluss können <a class="header-anchor" href="#was-sie-nach-abschluss-konnen" aria-label="Permalink to &quot;Was Sie nach Abschluss können&quot;">​</a></h2><p>Nach Abschluss dieser Lektion beherrschen Sie:</p><ul><li>Wie Sie qualitativ hochwertige Produktbeschreibungen erstellen, damit die KI Ihre Ideen versteht</li><li>Wie Sie den Checkpoint-Mechanismus nutzen, um die Ausgabequalität jeder Phase zu steuern</li><li>Wie Sie durch Nicht-Ziele klare Umfangsgrenzen definieren und Projektaufblähung verhindern</li><li>Wie Sie durch schrittweise Iterationen Ideen schnell validieren und kontinuierlich optimieren</li></ul><h2 id="ihre-aktuelle-herausforderung" tabindex="-1">Ihre aktuelle Herausforderung <a class="header-anchor" href="#ihre-aktuelle-herausforderung" aria-label="Permalink to &quot;Ihre aktuelle Herausforderung&quot;">​</a></h2><p>Sind Sie auch in diese Situationen geraten:</p><ul><li>&quot;Ich habe es doch klar gesagt, warum ist das Ergebnis nicht das, was ich will?&quot;</li><li>&quot;An einem Stelle unzufrieden, alles danach ist falsch – korrigieren ist schmerzhaft&quot;</li><li>&quot;Immer mehr Funktionen entstehen, Abschluss ist unmöglich&quot;</li><li>&quot;Alle Funktionen auf einmal machen wollen, aber nichts wird fertig&quot;</li></ul><h2 id="wann-diese-methode-nutzen" tabindex="-1">Wann diese Methode nutzen <a class="header-anchor" href="#wann-diese-methode-nutzen" aria-label="Permalink to &quot;Wann diese Methode nutzen&quot;">​</a></h2><p>Egal, ob Sie AI App Factory zum ersten Mal verwenden oder bereits Erfahrung haben, diese Best Practices helfen Ihnen:</p><ul><li><strong>Ausgabequalität verbessern</strong>: Die generierte Anwendung entspricht eher Ihren Erwartungen</li><li><strong>Korrekturzeit sparen</strong>: Fehlerakkumulation vermeiden, Probleme frühzeitig erkennen</li><li><strong>Projektumfang steuern</strong>: Auf MVP fokussieren, schnell liefern</li><li><strong>Entwicklungskosten senken</strong>: Phasenweise Validierung, unnötige Investitionen vermeiden</li></ul><h2 id="🎒-vorbereitungen-vor-dem-start" tabindex="-1">🎒 Vorbereitungen vor dem Start <a class="header-anchor" href="#🎒-vorbereitungen-vor-dem-start" aria-label="Permalink to &quot;🎒 Vorbereitungen vor dem Start&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Voraussetzungen</p><ul><li><a href="./../../start/getting-started/">Schnellstart</a> gelesen, um die Grundkonzepte von AI App Factory zu verstehen</li><li><a href="./../../start/pipeline-overview/">7-Phasen-Pipeline-Übersicht</a> gelesen, um den vollständigen Prozess zu verstehen</li><li>Mindestens eine vollständige Pipeline-Ausführung abgeschlossen (damit Sie ein intuitives Gefühl für die Ausgaben jeder Phase haben)</li></ul></div><h2 id="kernkonzepte" tabindex="-1">Kernkonzepte <a class="header-anchor" href="#kernkonzepte" aria-label="Permalink to &quot;Kernkonzepte&quot;">​</a></h2><p>Die Best Practices von AI App Factory drehen sich um vier Kernprinzipien:</p><ol><li><strong>Eingabequalität bestimmt Ausgabequalität</strong>: Klare, detaillierte Produktbeschreibung ist der erste Schritt zum Erfolg</li><li><strong>Checkpoints sind Qualitätsabwehr</strong>: Sorgfältige Bestätigung nach jeder Phase vermeidet Fehlerakkumulation</li><li><strong>MVP-Fokus</strong>: Klare Nicht-Ziele, Umfangskontrolle, schnelle Lieferung der Kernfunktionen</li><li><strong>Kontinuierliche Iteration</strong>: Zuerst die Kernidee validieren, dann Funktionen schrittweise erweitern</li></ol><p>Diese Prinzipien stammen aus der Zusammenfassung von Quellcode und Praxiserfahrung. Wenn Sie ihnen folgen, wird sich Ihre Entwicklungseffizienz vervielfachen.</p><h2 id="folgen-sie-mir" tabindex="-1">Folgen Sie mir <a class="header-anchor" href="#folgen-sie-mir" aria-label="Permalink to &quot;Folgen Sie mir&quot;">​</a></h2><h3 id="tipp-1-klare-produktbeschreibung-bereitstellen" tabindex="-1">Tipp 1: Klare Produktbeschreibung bereitstellen <a class="header-anchor" href="#tipp-1-klare-produktbeschreibung-bereitstellen" aria-label="Permalink to &quot;Tipp 1: Klare Produktbeschreibung bereitstellen&quot;">​</a></h3><h4 id="warum" tabindex="-1">Warum <a class="header-anchor" href="#warum" aria-label="Permalink to &quot;Warum&quot;">​</a></h4><p>Wenn die KI Ihre Ideen versteht, kann sie sich nur auf die von Ihnen bereitgestellten Textinformationen verlassen. Je klarer die Beschreibung, desto eher entspricht das generierte Ergebnis Ihren Erwartungen.</p><h4 id="wie" tabindex="-1">Wie <a class="header-anchor" href="#wie" aria-label="Permalink to &quot;Wie&quot;">​</a></h4><p><strong>Eine gute Produktbeschreibung enthält folgende Elemente</strong>:</p><ul><li><strong>Zielbenutzer</strong>: Wer wird dieses Produkt verwenden?</li><li><strong>Kernproblem</strong>: Welche Schwierigkeiten haben Benutzer?</li><li><strong>Lösung</strong>: Wie löst das Produkt dieses Problem?</li><li><strong>Schlüsselfunktionen</strong>: Welche Funktionen müssen enthalten sein?</li><li><strong>Nutzungsszenarien</strong>: Wann benutzen Benutzer das Produkt?</li><li><strong>Einschränkungen</strong>: Welche Einschränkungen oder speziellen Anforderungen gibt es?</li></ul><h4 id="vergleichsbeispiele" tabindex="-1">Vergleichsbeispiele <a class="header-anchor" href="#vergleichsbeispiele" aria-label="Permalink to &quot;Vergleichsbeispiele&quot;">​</a></h4><table tabindex="0"><thead><tr><th>❌ Schlechte Beschreibung</th><th>✅ Gute Beschreibung</th></tr></thead><tbody><tr><td>Mach eine Fitness-App</td><td>Eine App zur Unterstützung von Fitness-Anfängern beim Aufzeichnen von Trainingseinheiten. Unterstützt Aufzeichnung von Trainingsart, Dauer, verbrannten Kalorien und Anzeige der wöchentlichen Trainingsstatistiken. Zielgruppe sind junge Menschen, die gerade mit dem Training beginnen. Die Kernfunktionen sind schnelle Aufzeichnung und Fortschrittsanzeige, ohne soziales Teilen oder kostenpflichtige Funktionen</td></tr><tr><td>Mach eine Buchhaltungs-App</td><td>Eine mobile Buchhaltungs-App zur schnellen Aufzeichnung täglicher Ausgaben für junge Menschen. Hauptfunktionen sind Betrag eingeben, Kategorie auswählen (Ernährung, Verkehr, Unterhaltung, Sonstiges), monatliche Gesamtausgaben und Kategoriestatistiken anzeigen. Unterstützt Offline-Nutzung, Daten werden nur lokal gespeichert</td></tr><tr><td>Mach ein Aufgabenverwaltungs-Tool</td><td>Ein einfaches Tool zur Aufgabenverwaltung für kleine Teams. Unterstützt Erstellen von Aufgaben, Zuweisen von Mitgliedern, Festlegen von Fristen, Anzeigen der Aufgabenliste. Teammitglieder können Aufgabenstatus teilen. Kein komplexer Workflow oder Berechtigungsmanagement erforderlich</td></tr></tbody></table><h4 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h4><ul><li>[ ] Die Beschreibung definiert die Zielbenutzer klar</li><li>[ ] Die Beschreibung erklärt das Kernproblem der Benutzer</li><li>[ ] Die Beschreibung listet die Schlüsselfunktionen auf (nicht mehr als 5)</li><li>[ ] Die Beschreibung enthält Einschränkungen oder Nicht-Ziele</li></ul><hr><h3 id="tipp-2-sorgfaltige-bestatigung-an-checkpoints" tabindex="-1">Tipp 2: Sorgfältige Bestätigung an Checkpoints <a class="header-anchor" href="#tipp-2-sorgfaltige-bestatigung-an-checkpoints" aria-label="Permalink to &quot;Tipp 2: Sorgfältige Bestätigung an Checkpoints&quot;">​</a></h3><h4 id="warum-1" tabindex="-1">Warum <a class="header-anchor" href="#warum-1" aria-label="Permalink to &quot;Warum&quot;">​</a></h4><p>Nach Abschluss jeder Phase der Pipeline wird an einem Checkpoint pausiert und auf Ihre Bestätigung gewartet. Dies ist die <strong>Qualitätsabwehr</strong>, die es Ihnen ermöglicht, Probleme frühzeitig zu erkennen und zu vermeiden, dass sie sich in nachfolgenden Phasen ausbreiten.</p><p>Wenn Sie in dieser Phase ein Problem entdecken, müssen Sie nur die aktuelle Phase erneut ausführen. Wenn Sie es erst am Ende entdecken, müssen Sie möglicherweise mehrere Phasen zurückrollen, was viel Zeit und Tokens verschwendet.</p><h4 id="wie-1" tabindex="-1">Wie <a class="header-anchor" href="#wie-1" aria-label="Permalink to &quot;Wie&quot;">​</a></h4><p><strong>Bestätigen Sie bei jedem Checkpoint folgende Inhalte</strong>:</p><p><strong>Bootstrap-Phase Checkpoint</strong>:</p><ul><li>[ ] Die Problemdefinition in <code>input/idea.md</code> ist korrekt</li><li>[ ] Die Zielbenutzer-Persona ist klar und spezifiziert</li><li>[ ] Das Kernwertversprechen ist eindeutig</li><li>[ ] Die Annahmen sind vernünftig</li></ul><p><strong>PRD-Phase Checkpoint</strong>:</p><ul><li>[ ] User Stories sind klar und enthalten Akzeptanzkriterien</li><li>[ ] Funktionsliste nicht mehr als 7 (MVP-Prinzip)</li><li>[ ] Nicht-Ziele (Non-Goals) sind klar aufgelistet</li><li>[ ] Keine technischen Details enthalten (wie React, API, Datenbank)</li></ul><p><strong>UI-Phase Checkpoint</strong>:</p><ul><li>[ ] Seitenstruktur ist vernünftig, nicht mehr als 3 Seiten</li><li>[ ] Das Prototyp kann im Browser angezeigt werden</li><li>[ ] Interaktionsfluss ist klar</li><li>[ ] Ästhetischer Stil ist ausgeprägt (vermeiden Sie gängige KI-Stile)</li></ul><p><strong>Tech-Phase Checkpoint</strong>:</p><ul><li>[ ] Tech-Stack-Wahl ist vernünftig und entspricht dem MVP-Prinzip</li><li>[ ] Datenmodell-Design ist einfach, Tabellenanzahl nicht mehr als 10</li><li>[ ] API-Endpunkt-Liste ist vollständig</li><li>[ ] Keine übermäßigen Designs wie Microservices, Caching eingeführt</li></ul><p><strong>Code-Phase Checkpoint</strong>:</p><ul><li>[ ] Frontend- und Backend-Code-Struktur ist vollständig</li><li>[ ] Enthält Testfälle</li><li>[ ] Keine offensichtlichen <code>any</code>-Typen</li><li>[ ] Enthält README.md mit Anweisungen zur Ausführung</li></ul><p><strong>Validation-Phase Checkpoint</strong>:</p><ul><li>[ ] Keine schwerwiegenden Sicherheitsprobleme im Validierungsbericht</li><li>[ ] Testabdeckung &gt; 60%</li><li>[ ] Keine Konflikte bei Abhängigkeitsinstallation</li><li>[ ] TypeScript-Typprüfung bestanden</li></ul><p><strong>Preview-Phase Checkpoint</strong>:</p><ul><li>[ ] README.md enthält vollständige Ausführungsanweisungen</li><li>[ ] Docker-Konfiguration kann erfolgreich gebaut werden</li><li>[ ] Frontend- und Backend-Services können lokal gestartet werden</li><li>[ ] Enthält Umgebungsvariablen-Konfigurationsanweisungen</li></ul><h4 id="checkpoint-bestatigungsprozess" tabindex="-1">Checkpoint-Bestätigungsprozess <a class="header-anchor" href="#checkpoint-bestatigungsprozess" aria-label="Permalink to &quot;Checkpoint-Bestätigungsprozess&quot;">​</a></h4><p>Bei jedem Checkpoint bietet das System folgende Optionen:</p><ul><li><strong>Weiter</strong>: Wenn die Ausgabe den Erwartungen entspricht, zur nächsten Phase fortfahren</li><li><strong>Wiederholen</strong>: Wenn die Ausgabe Probleme hat, Korrekturvorschläge geben und aktuelle Phase erneut ausführen</li><li><strong>Pausieren</strong>: Wenn Sie mehr Informationen benötigen oder die Idee anpassen möchten, Pipeline pausieren</li></ul><p><strong>Entscheidungsprinzipien</strong>:</p><ul><li>✅ <strong>Weiter</strong>: Alle Prüfpunkte erfüllen die Anforderungen</li><li>⚠️ <strong>Wiederholen</strong>: Kleine Probleme (Format, Auslassungen, Details), können sofort korrigiert werden</li><li>🛑 <strong>Pausieren</strong>: Schwerwiegende Probleme (falsche Richtung, Umfang außer Kontrolle, nicht korrigierbar), Neuplanung erforderlich</li></ul><h4 id="fallstrick-hinweis" tabindex="-1">Fallstrick-Hinweis <a class="header-anchor" href="#fallstrick-hinweis" aria-label="Permalink to &quot;Fallstrick-Hinweis&quot;">​</a></h4><div class="danger custom-block"><p class="custom-block-title">Häufige Fehler</p><p><strong>Überspringen Sie nicht die Checkpoint-Bestätigung, um &quot;schnell fertig zu werden&quot;!</strong></p><p>Die Pipeline ist so konzipiert, dass sie &quot;nach jeder Phase zur Bestätigung pausiert&quot;, damit Sie Probleme rechtzeitig erkennen. Wenn Sie gewohnheitsmäßig auf &quot;Weiter&quot; klicken und erst am Ende Probleme entdecken, müssen Sie möglicherweise:</p><ul><li>Mehrere Phasen zurückrollen</li><li>Viel Arbeit erneut ausführen</li><li>Viele Tokens verschwenden</li></ul><p>Denken Sie daran: <strong>Der Zeitaufwand für Checkpoint-Bestätigung ist viel geringer als die Zeitkosten für das Zurückrollen und Neumachen</strong>.</p></div><hr><h3 id="tipp-3-nicht-ziele-zur-umfangskontrolle-nutzen" tabindex="-1">Tipp 3: Nicht-Ziele zur Umfangskontrolle nutzen <a class="header-anchor" href="#tipp-3-nicht-ziele-zur-umfangskontrolle-nutzen" aria-label="Permalink to &quot;Tipp 3: Nicht-Ziele zur Umfangskontrolle nutzen&quot;">​</a></h3><h4 id="warum-2" tabindex="-1">Warum <a class="header-anchor" href="#warum-2" aria-label="Permalink to &quot;Warum&quot;">​</a></h4><p><strong>Nicht-Ziele (Non-Goals) sind die Kernwaffe der MVP-Entwicklung</strong>. Durch die klare Auflistung von &quot;was nicht getan wird&quot;, kann Scope Creep effektiv verhindert werden.</p><p>Die Wurzel vieler gescheiterter Projekte ist nicht zu wenige Funktionen, sondern zu viele. Jede neue Funktion erhöht Komplexität, Entwicklungszeit und Wartungskosten. Nur durch klare Grenzen und Fokus auf Kernwerte können Sie schnell liefern.</p><h4 id="wie-2" tabindex="-1">Wie <a class="header-anchor" href="#wie-2" aria-label="Permalink to &quot;Wie&quot;">​</a></h4><p><strong>In der Bootstrap-Phase, Nicht-Ziele klar auflisten</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Nicht-Ziele (Funktionen, die in dieser Version nicht getan werden)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Keine Unterstützung für Mehrbenutzer-Kollaboration</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Keine Unterstützung für Echtzeit-Synchronisation</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Keine Integration von Drittanbieterdiensten (wie Zahlung, Karten)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">4.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Keine Datenanalyse oder Berichtsfunktionen</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">5.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Keine Social-Sharing-Funktionen</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">6.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Keine Benutzer-Authentifizierung oder Anmeldefunktion erforderlich</span></span></code></pre></div><p><strong>In der PRD-Phase, Nicht-Ziele als eigenständigen Abschnitt</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Nicht-Ziele (Explizit nicht in dieser Version)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Die folgenden Funktionen haben zwar Wert, sind aber nicht im Rahmen dieses MVP:</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Funktion | Begründung | Zukünftige Planung |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| --- | --- | --- |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Mehrbenutzer-Kollaboration | Fokus auf Einzelbenutzer | In v2.0 in Betracht ziehen |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Echtzeit-Synchronisation | Erhöht technische Komplexität | Nach starkem Benutzerfeedback in Betracht ziehen |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Zahlungsintegration | Kein Kernwert | In v1.5 in Betracht ziehen |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Datenanalyse | MVP nicht erforderlich | In v2.0 in Betracht ziehen |</span></span></code></pre></div><h4 id="kriterien-fur-nicht-ziele" tabindex="-1">Kriterien für Nicht-Ziele <a class="header-anchor" href="#kriterien-fur-nicht-ziele" aria-label="Permalink to &quot;Kriterien für Nicht-Ziele&quot;">​</a></h4><p><strong>Wie zu entscheiden, ob etwas als Nicht-Ziel gelten soll</strong>:</p><ul><li>❌ Diese Funktion ist zur Validierung der Kernidee nicht erforderlich → Als Nicht-Ziel</li><li>❌ Diese Funktion erhöht die technische Komplexität erheblich → Als Nicht-Ziel</li><li>❌ Diese Funktion kann manuell ersetzt werden → Als Nicht-Ziel</li><li>✅ Diese Funktion ist der Grund für die Existenz des Produkts → Muss enthalten sein</li></ul><h4 id="fallstrick-hinweis-1" tabindex="-1">Fallstrick-Hinweis <a class="header-anchor" href="#fallstrick-hinweis-1" aria-label="Permalink to &quot;Fallstrick-Hinweis&quot;">​</a></h4><div class="warning custom-block"><p class="custom-block-title">Scope Creep-Falle</p><p><strong>Typische Signale von Scope Creep</strong>:</p><ol><li>&quot;Ist doch einfach, einfach eine hinzufügen...&quot;</li><li>&quot;Konkurrenzprodukte haben diese Funktion, wir müssen auch...&quot;</li><li>&quot;Benutzer könnten das brauchen, machen wir es einfach...&quot;</li><li>&quot;Diese Funktion ist interessant, kann die Produkt-Highlights verbessern...&quot;</li></ol><p><strong>Wenn Sie auf diese Ideen stoßen, fragen Sie sich drei Fragen</strong>:</p><ol><li>Ist diese Funktion nützlich, um die Kernidee zu validieren?</li><li>Kann das Produkt ohne diese Funktion noch verwendet werden?</li><li>Wird das Hinzufügen dieser Funktion die Lieferzeit verzögern?</li></ol><p>Wenn die Antworten &quot;nicht erforderlich&quot;, &quot;kann verwendet&quot;, &quot;verzögert&quot;, dann entscheiden Sie sich für Nicht-Ziele.</p></div><hr><h3 id="tipp-4-schrittweise-iteration-schnelle-validierung" tabindex="-1">Tipp 4: Schrittweise Iteration, schnelle Validierung <a class="header-anchor" href="#tipp-4-schrittweise-iteration-schnelle-validierung" aria-label="Permalink to &quot;Tipp 4: Schrittweise Iteration, schnelle Validierung&quot;">​</a></h3><h4 id="warum-3" tabindex="-1">Warum <a class="header-anchor" href="#warum-3" aria-label="Permalink to &quot;Warum&quot;">​</a></h4><p><strong>Der Kerngedanke von MVP (Minimum Viable Product) ist die schnelle Validierung von Ideen</strong>, nicht auf einmal perfekt zu machen.</p><p>Durch iterative Entwicklung können Sie:</p><ul><li>Frühes Benutzerfeedback erhalten</li><li>Rechtzeitig die Richtung anpassen</li><li>Sunk Costs reduzieren</li><li>Entwicklungsmotivation aufrechterhalten</li></ul><h4 id="wie-3" tabindex="-1">Wie <a class="header-anchor" href="#wie-3" aria-label="Permalink to &quot;Wie&quot;">​</a></h4><p><strong>Schritte der iterativen Entwicklung</strong>:</p><p><strong>Runde 1: Kernfunktionsvalidierung</strong></p><ol><li>Verwenden Sie AI App Factory, um die erste Version der Anwendung zu generieren</li><li>Nur die 3-5 wichtigsten Kernfunktionen enthalten</li><li>Schnell ausführen und testen</li><li>Echte Benutzern das Prototyp zeigen, Feedback sammeln</li></ol><p><strong>Runde 2: Optimierung basierend auf Feedback</strong></p><ol><li>Basierend auf Benutzerfeedback die wichtigsten Verbesserungspunkte priorisieren</li><li><code>input/idea.md</code> oder <code>artifacts/prd/prd.md</code> ändern</li><li>Verwenden Sie <code>factory run &lt;stage&gt;</code>, um ab der entsprechenden Phase erneut auszuführen</li><li>Neue Version generieren und testen</li></ol><p><strong>Runde 3: Funktionserweiterung</strong></p><ol><li>Bewerten, ob das Kernziel erreicht wurde</li><li>2-3 hochwertige Funktionen auswählen</li><li>Durch Pipeline generieren und integrieren</li><li>Kontinuierlich iterieren, schrittweise perfektionieren</li></ol><h4 id="iteratives-praxisbeispiel" tabindex="-1">Iteratives Praxisbeispiel <a class="header-anchor" href="#iteratives-praxisbeispiel" aria-label="Permalink to &quot;Iteratives Praxisbeispiel&quot;">​</a></h4><p><strong>Szenario</strong>: Sie möchten eine Aufgabenverwaltungsanwendung erstellen</p><p><strong>Runde 1 MVP</strong>:</p><ul><li>Kernfunktionen: Aufgabe erstellen, Listenanzeige, als erledigt markieren</li><li>Nicht-Ziele: Mitgliederverwaltung, Berechtigungssteuerung, Erinnerungsbenachrichtigungen</li><li>Lieferzeit: 1 Tag</li></ul><p><strong>Runde 2 Optimierung</strong> (basierend auf Feedback):</p><ul><li>Benutzerfeedback: Aufgaben mit Tags versehen wollen</li><li>PRD ändern, Funktion &quot;Tag-Klassifizierung&quot; hinzufügen</li><li>Pipeline ab UI-Phase erneut ausführen</li><li>Lieferzeit: Halber Tag</li></ul><p><strong>Runde 3 Erweiterung</strong> (nach erfolgreicher Validierung):</p><ul><li>Mitgliederverwaltungsfunktion hinzufügen</li><li>Frist-Erinnerungen hinzufügen</li><li>Aufgaben-Kommentarfunktion hinzufügen</li><li>Lieferzeit: 2 Tage</li></ul><h4 id="checkpoint-✅-1" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅-1" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h4><p>Vor jeder Iteration prüfen:</p><ul><li>[ ] Ob die neue Funktion mit dem Kernziel übereinstimmt</li><li>[ ] Ob die neue Funktion durch Benutzeranforderungen gestützt wird</li><li>[ ] Ob die neue Funktion die Komplexität erheblich erhöht</li><li>[ ] Ob klare Akzeptanzkriterien vorliegen</li></ul><hr><h2 id="fortgeschrittene-tipps" tabindex="-1">Fortgeschrittene Tipps <a class="header-anchor" href="#fortgeschrittene-tipps" aria-label="Permalink to &quot;Fortgeschrittene Tipps&quot;">​</a></h2><h3 id="tipp-5-tokens-durch-separate-sessions-sparen" tabindex="-1">Tipp 5: Tokens durch separate Sessions sparen <a class="header-anchor" href="#tipp-5-tokens-durch-separate-sessions-sparen" aria-label="Permalink to &quot;Tipp 5: Tokens durch separate Sessions sparen&quot;">​</a></h3><h4 id="warum-4" tabindex="-1">Warum <a class="header-anchor" href="#warum-4" aria-label="Permalink to &quot;Warum&quot;">​</a></h4><p>Lange Laufzeit der Pipeline führt zur Anhäufung von Kontext und verbraucht viele Tokens. <strong>Ausführung in separaten Sessions</strong> ermöglicht jeder Phase einen sauberen Kontext und senkt die Nutzungskosten erheblich.</p><h4 id="wie-4" tabindex="-1">Wie <a class="header-anchor" href="#wie-4" aria-label="Permalink to &quot;Wie&quot;">​</a></h4><p><strong>Wählen Sie bei jedem Checkpoint &quot;Neue Session fortsetzen&quot;</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># In einem neuen Befehlsfenster ausführen</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> continue</span></span></code></pre></div><p>Das System automatisch:</p><ol><li>Liest <code>.factory/state.json</code> zum Wiederherstellen des Status</li><li>Startet ein neues Claude Code-Fenster</li><li>Führt ab der nächsten ausstehenden Phase fort</li><li>Lädt nur die für diese Phase erforderlichen Eingabedateien</li></ol><p><strong>Vergleich</strong>:</p><table tabindex="0"><thead><tr><th>Methode</th><th>Vorteile</th><th>Nachteile</th></tr></thead><tbody><tr><td>In gleicher Session fortfahren</td><td>Einfach, kein Fensterwechsel erforderlich</td><td>Kontext akkumuliert, hoher Token-Verbrauch</td></tr><tr><td>Neue Session fortfahren</td><td>Jede Phase hat sauberen Kontext, spart Tokens</td><td>Fensterwechsel erforderlich</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Empfohlene Vorgehensweise</p><p><strong>Für große Projekte oder begrenzte Token-Budgets wird dringend empfohlen, &quot;Neue Session fortsetzen&quot; zu verwenden</strong>.</p><p>Detaillierte Erklärung siehe <a href="./../../advanced/context-optimization/">Kontextoptimierung</a> Tutorial.</p></div><hr><h3 id="tipp-6-umgang-mit-fehlern-und-wiederholungen" tabindex="-1">Tipp 6: Umgang mit Fehlern und Wiederholungen <a class="header-anchor" href="#tipp-6-umgang-mit-fehlern-und-wiederholungen" aria-label="Permalink to &quot;Tipp 6: Umgang mit Fehlern und Wiederholungen&quot;">​</a></h3><h4 id="warum-5" tabindex="-1">Warum <a class="header-anchor" href="#warum-5" aria-label="Permalink to &quot;Warum&quot;">​</a></h4><p>Bei der Pipeline-Ausführung können Fehler auftreten (ungenügende Eingaben, Berechtigungsprobleme, Code-Fehler usw.). Das Verständnis, wie man mit Fehlern umgeht, ermöglicht Ihnen eine schnellere Fortschrittsfortsetzung.</p><h4 id="wie-5" tabindex="-1">Wie <a class="header-anchor" href="#wie-5" aria-label="Permalink to &quot;Wie&quot;">​</a></h4><p><strong>Best Practices für Fehlerbehandlung</strong> (siehe <code>failure.policy.md:267-274</code>):</p><ol><li><strong>Frühes Scheitern</strong>: Probleme frühzeitig erkennen, Verschwendung von Zeit in nachfolgenden Phasen vermeiden</li><li><strong>Detaillierte Logs</strong>: Ausreichende Kontextinformationen aufzeichnen, um Probleme zu beheben</li><li><strong>Atomare Operationen</strong>: Die Ausgabe jeder Phase sollte atomar sein, um ein Rollback zu ermöglichen</li><li><strong>Beweise behalten</strong>: Fehlgeschlagene Ergebnisse archivieren, bevor erneut versucht wird, um Vergleichsanalysen zu ermöglichen</li><li><strong>Schrittweise Wiederholung</strong>: Bei Wiederholungen konkretere Anleitungen bereitstellen, anstatt einfache Wiederholung</li></ol><p><strong>Typische Fehler-Szenarien</strong>:</p><table tabindex="0"><thead><tr><th>Fehlertyp</th><th>Symptom</th><th>Lösungsansatz</th></tr></thead><tbody><tr><td>Ausgabe fehlt</td><td><code>input/idea.md</code> existiert nicht</td><td>Wiederholen, Schreibpfad prüfen</td></tr><tr><td>Scope Creep</td><td>Funktionsanzahl &gt; 7</td><td>Wiederholen, auf MVP reduzieren anfordern</td></tr><tr><td>Technischer Fehler</td><td>TypeScript-Kompilierung fehlgeschlagen</td><td>Typdefinition prüfen, wiederholen</td></tr><tr><td>Berechtigungsproblem</td><td>Agent schreibt in nicht autorisiertes Verzeichnis</td><td>Fähigkeitsgrenzen-Matrix prüfen</td></tr></tbody></table><p><strong>Fehlerwiederherstellungs-Checkliste</strong>:</p><ul><li>[ ] Fehlerursache ist klar</li><li>[ ] Korrekturansatz ist implementiert</li><li>[ ] Verwandte Konfigurationen sind aktualisiert</li><li>[ ] Von der fehlgeschlagenen Phase neu beginnen</li></ul><div class="tip custom-block"><p class="custom-block-title">Fehler sind normal</p><p><strong>Fürchten Sie sich nicht vor Fehlern!</strong> AI App Factory verfügt über einen umfassenden Fehlerbehandlungsmechanismus:</p><ul><li>Jede Phase erlaubt eine automatische Wiederholung</li><li>Fehlgeschlagene Ergebnisse werden automatisch in <code>artifacts/_failed/</code> archiviert</li><li>Kann zum letzten erfolgreichen Checkpoint zurückrollen</li></ul><p>Wenn Sie auf Fehler stoßen, analysieren Sie ruhig die Ursache und befolgen Sie die Fehlerbehandlungsstrategie.</p></div><hr><h2 id="zusammenfassung-dieser-lektion" tabindex="-1">Zusammenfassung dieser Lektion <a class="header-anchor" href="#zusammenfassung-dieser-lektion" aria-label="Permalink to &quot;Zusammenfassung dieser Lektion&quot;">​</a></h2><p>Diese Lektion stellte die sechs Best Practices von AI App Factory vor:</p><ol><li><strong>Klare Produktbeschreibung</strong>: Detaillierte Beschreibung von Zielbenutzern, Kernproblemen, Schlüsselfunktionen und Einschränkungen</li><li><strong>Sorgfältige Checkpoint-Bestätigung</strong>: Nach jeder Phase die Ausgabequalität prüfen, Fehlerakkumulation vermeiden</li><li><strong>Nicht-Ziele zur Umfangskontrolle nutzen</strong>: Klare Auflistung von nicht getanen Funktionen, Scope Creep verhindern</li><li><strong>Schrittweise Iteration</strong>: Zuerst Kernidee validieren, dann basierend auf Benutzerfeedback schrittweise erweitern</li><li><strong>Separate Sessions zum Tokensparen</strong>: Bei jedem Checkpoint neue Session erstellen, Nutzungskosten senken</li><li><strong>Richtige Fehlerbehandlung</strong>: Fehlerbehandlungsmechanismus nutzen, Fortschritt schnell wiederherstellen</li></ol><p>Wenn Sie diese Best Practices befolgen, wird Ihre AI App Factory-Nutzungserfahrung reibungsloser verlaufen, die Qualität der generierten Anwendungen höher und die Entwicklungseffizienz vervielfacht.</p><hr><h2 id="vorschau-auf-nachste-lektion" tabindex="-1">Vorschau auf nächste Lektion <a class="header-anchor" href="#vorschau-auf-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../../appendix/cli-commands/">CLI-Befehlsreferenz</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Alle Parameter und Optionen des factory init-Befehls</li><li>Wie der factory run-Befehl ab einer bestimmten Phase startet</li><li>Wie der factory continue-Befehl eine neue Session erstellt und fortfährt</li><li>Wie factory status und factory list Projektinformationen anzeigen</li><li>Wie factory reset den Projektstatus zurücksetzt</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken zum Anzeigen der Quellcode-Position</strong></summary><blockquote><p>Aktualisiert: 2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilen</th></tr></thead><tbody><tr><td>Produktbeschreibung-Tipps</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/README.md#L186-L210" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>186-210</td></tr><tr><td>Checkpoint-Mechanismus</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md#L98-L112" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>98-112</td></tr><tr><td>Nicht-Ziel-Kontrolle</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/README.md#L199-L203" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>199-203</td></tr><tr><td>Fehlerbehandlungsstrategie</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/failure.policy.md#L267-L274" target="_blank" rel="noreferrer"><code>policies/failure.policy.md</code></a></td><td>267-274</td></tr><tr><td>Kontext-Isolation</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/context-isolation.md#L10-L42" target="_blank" rel="noreferrer"><code>policies/context-isolation.md</code></a></td><td>10-42</td></tr><tr><td>Code-Standards</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/code-standards.md" target="_blank" rel="noreferrer"><code>policies/code-standards.md</code></a></td><td>Volltext</td></tr></tbody></table><p><strong>Wichtige Konstanten</strong>:</p><ul><li><code>MAX_RETRY_COUNT = 1</code>: Jede Phase erlaubt standardmäßig eine automatische Wiederholung</li></ul><p><strong>Wichtige Regeln</strong>:</p><ul><li>Anzahl der Must-Have-Funktionen ≤ 7 (MVP-Prinzip)</li><li>Seitenanzahl ≤ 3 (UI-Phase)</li><li>Datenmodellanzahl ≤ 10 (Tech-Phase)</li><li>Testabdeckung &gt; 60% (Validation-Phase)</li></ul></details>`,131)])])}const p=n(s,[["render",a]]);export{g as __pageData,p as default};
